import { Injectable } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { Observable } from 'rxjs';

export interface OptimizeRequest {
    query: string;
    database_type: string;
    context?: string;
}

export interface OptimizeResponse {
    original_query: string;
    optimized_query: string;
    tips: string[];
    estimated_improvement: string;
    explanation: string;
}

export interface QueryHistory {
    id: number;
    original_query: string;
    optimized_query: string;
    database_type: string;
    created_at: string;
    estimated_improvement: string;
}

export interface StatsResponse {
    total_queries_analyzed: number;
    by_database_type: {
        [key: string]: number;
    };
}

@Injectable({
    providedIn: 'root'
})
export class SqlOptimizerService {
    private apiUrl = 'http://localhost:8000'; // Change to your backend URL

    constructor(private http: HttpClient) {
        // Allow environment-based API URL
        const envUrl = (window as any)['API_URL'];
        if (envUrl) {
            this.apiUrl = envUrl;
        }
    }

    /**
     * Optimize a SQL query
     */
    optimizeQuery(request: OptimizeRequest): Observable<OptimizeResponse> {
        return this.http.post<OptimizeResponse>(
            `${this.apiUrl}/optimize`,
            request
        );
    }

    /**
     * Get query history
     */
    getHistory(limit: number = 20): Observable<QueryHistory[]> {
        return this.http.get<QueryHistory[]>(
            `${this.apiUrl}/history?limit=${limit}`
        );
    }

    /**
     * Get statistics
     */
    getStats(): Observable<StatsResponse> {
        return this.http.get<StatsResponse>(
            `${this.apiUrl}/stats`
        );
    }

    /**
     * Health check
     */
    healthCheck(): Observable<any> {
        return this.http.get(
            `${this.apiUrl}/health`
        );
    }
}
